const { ApolloServer, gql } = require('apollo-server');
const DataLoader = require('dataloader');

const users = [
  { id: '1', name: 'Alice', email: 'alice@example.com' },
  { id: '2', name: 'Bob', email: 'bob@example.com' },
  { id: '3', name: 'Charlie', email: 'charlie@example.com' }
];

const posts = [
  { id: '1', title: 'First Post', content: 'Hello World', authorId: '1' },
  { id: '2', title: 'Second Post', content: 'GraphQL is great', authorId: '2' },
  { id: '3', title: 'Third Post', content: 'Node.js rocks', authorId: '1' },
  { id: '4', title: 'Fourth Post', content: 'Apollo Server', authorId: '3' }
];

const comments = [
  { id: '1', text: 'Great post!', postId: '1', authorId: '2' },
  { id: '2', text: 'Thanks for sharing', postId: '1', authorId: '3' },
  { id: '3', text: 'Interesting', postId: '2', authorId: '1' },
  { id: '4', text: 'I agree', postId: '2', authorId: '3' },
  { id: '5', text: 'Nice work', postId: '3', authorId: '2' }
];

const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    email: String!
    posts: [Post!]!
    comments: [Comment!]!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    author: User!
    comments: [Comment!]!
  }

  type Comment {
    id: ID!
    text: String!
    post: Post!
    author: User!
  }

  type Query {
    users: [User!]!
    user(id: ID!): User
    posts: [Post!]!
    post(id: ID!): Post
    comments: [Comment!]!
    comment(id: ID!): Comment
  }
`;

class QueryDepthTracker {
  constructor(maxDepth = 10) {
    this.maxDepth = maxDepth;
    this.depthMap = new WeakMap();
  }

  track(info, parent) {
    const depth = this.calculateDepth(info, parent);
    if (depth > this.maxDepth) {
      throw new Error(`Query depth exceeds maximum allowed depth of ${this.maxDepth}`);
    }
    return depth;
  }

  calculateDepth(info, parent) {
    let depth = 0;
    let currentParent = parent;
    
    while (currentParent) {
      depth++;
      currentParent = this.depthMap.get(currentParent);
    }
    
    return depth;
  }

  setParent(child, parent) {
    this.depthMap.set(child, parent);
  }
}

class QueryComplexityTracker {
  constructor(maxComplexity = 1000) {
    this.maxComplexity = maxComplexity;
    this.complexity = 0;
  }

  addComplexity(cost) {
    this.complexity += cost;
    if (this.complexity > this.maxComplexity) {
      throw new Error(`Query complexity exceeds maximum allowed complexity of ${this.maxComplexity}`);
    }
  }

  getComplexity() {
    return this.complexity;
  }
}

const resolvers = {
  Query: {
    users: (_, __, context) => {
      context.complexityTracker.addComplexity(1);
      return users;
    },
    user: (_, { id }, context) => {
      context.complexityTracker.addComplexity(1);
      return users.find(u => u.id === id);
    },
    posts: (_, __, context) => {
      context.complexityTracker.addComplexity(1);
      return posts;
    },
    post: (_, { id }, context) => {
      context.complexityTracker.addComplexity(1);
      return posts.find(p => p.id === id);
    },
    comments: (_, __, context) => {
      context.complexityTracker.addComplexity(1);
      return comments;
    },
    comment: (_, { id }, context) => {
      context.complexityTracker.addComplexity(1);
      return comments.find(c => c.id === id);
    }
  },
  User: {
    posts: (parent, _, context, info) => {
      context.depthTracker.track(info, parent);
      context.complexityTracker.addComplexity(2);
      
      const userPosts = posts.filter(p => p.authorId === parent.id);
      userPosts.forEach(post => context.depthTracker.setParent(post, parent));
      return userPosts;
    },
    comments: (parent, _, context, info) => {
      context.depthTracker.track(info, parent);
      context.complexityTracker.addComplexity(2);
      
      const userComments = comments.filter(c => c.authorId === parent.id);
      userComments.forEach(comment => context.depthTracker.setParent(comment, parent));
      return userComments;
    }
  },
  Post: {
    author: (parent, _, context, info) => {
      context.depthTracker.track(info, parent);
      context.complexityTracker.addComplexity(1);
      
      const author = context.loaders.userLoader.load(parent.authorId);
      return author.then(user => {
        context.depthTracker.setParent(user, parent);
        return user;
      });
    },
    comments: (parent, _, context, info) => {
      context.depthTracker.track(info, parent);
      context.complexityTracker.addComplexity(2);
      
      const postComments = comments.filter(c => c.postId === parent.id);
      postComments.forEach(comment => context.depthTracker.setParent(comment, parent));
      return postComments;
    }
  },
  Comment: {
    post: (parent, _, context, info) => {
      context.depthTracker.track(info, parent);
      context.complexityTracker.addComplexity(1);
      
      const post = context.loaders.postLoader.load(parent.postId);
      return post.then(p => {
        context.depthTracker.setParent(p, parent);
        return p;
      });
    },
    author: (parent, _, context, info) => {
      context.depthTracker.track(info, parent);
      context.complexityTracker.addComplexity(1);
      
      const author = context.loaders.userLoader.load(parent.authorId);
      return author.then(user => {
        context.depthTracker.setParent(user, parent);
        return user;
      });
    }
  }
};

const createUserLoader = () => {
  return new DataLoader(async (ids) => {
    return ids.map(id => users.find(u => u.id === id));
  });
};

const createPostLoader = () => {
  return new DataLoader(async (ids) => {
    return ids.map(id => posts.find(p => p.id === id));
  });
};

const createCommentLoader = () => {
  return new DataLoader(async (ids) => {
    return ids.map(id => comments.find(c => c.id === id));
  });
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: () => ({
    loaders: {
      userLoader: createUserLoader(),
      postLoader: createPostLoader(),
      commentLoader: createCommentLoader()
    },
    depthTracker: new QueryDepthTracker(10),
    complexityTracker: new QueryComplexityTracker(1000)
  }),
  formatError: (error) => {
    console.error('GraphQL Error:', error);
    return {
      message: error.message,
      locations: error.locations,
      path: error.path
    };
  },
  introspection: process.env.NODE_ENV !== 'production',
  playground: process.env.NODE_ENV !== 'production'
});

server.listen({ port: 4000 }).then(({ url }) => {
  console.log(`Server ready at ${url}`);
});